= 'applied' AND @NewStatus = 'verified') OR\r\n        (@OldStatus = 'verified' AND @NewStatus = 'shortlisted') OR\r\n        (@OldStatus = 'shortlisted' AND @NewStatus IN ('admitted', 'rejected'))\r\n    )\r\n    BEGIN\r\n        UPDATE AdmissionApplications\r\n        SET Status = @NewStatus,\r\n            UpdatedAt = SYSDATETIME()\r\n        WHERE ApplicationId = @ApplicationId;\r\n\r\n        INSERT INTO AdmissionStatusHistory (\r\n            ApplicationId,\r\n            OldStatus,\r\n            NewStatus,\r\n            ChangedBy\r\n        )\r\n        VALUES (\r\n            @ApplicationId,\r\n            @OldStatus,\r\n            @NewStatus,\r\n            @ChangedBy\r\n        );\r\n    END\r\n    ELSE\r\n    BEGIN\r\n        THROW 50001, 'Invalid status transition', 1;\r\n    END\r\nEND;\r\nGO\r\n"],"metadata":{"urn":"Server[@Name='DESKTOP-FINRPDH\\SQLEXPRESS']/Database[@Name='CampusAdmissionDB']/StoredProcedure[@Name='sp_ChangeAdmissionStatus' and @Schema='dbo']","object_type":"StoredProcedure"}},{"cell_type":"markdown","source":["# [dbo].[sp_CreateAdmissionApplication]"],"metadata":{"urn":"Server[@Name='DESKTOP-FINRPDH\\SQLEXPRESS']/Database[@Name='CampusAdmissionDB']/StoredProcedure[@Name='sp_CreateAdmissionApplication' and @Schema='dbo']","object_type":"StoredProcedure"}},{"outputs":[],"execution_count":0,"cell_type":"code","source":["/****** Object:  StoredProcedure [dbo].[sp_CreateAdmissionApplication]    Script Date: 2/24/2026 3:59:14 PM ******/\r\nSET ANSI_NULLS ON\r\n","GO\r\n","SET QUOTED_IDENTIFIER ON\r\n","GO\r\n","CREATE PROCEDURE [dbo].[sp_CreateAdmissionApplication]\r\n    @ApplicationNumber NVARCHAR(50),\r\n    @StudentName NVARCHAR(100),\r\n    @Email NVARCHAR(150),\r\n    @Phone NVARCHAR(20),\r\n    @CourseId INT,\r\n    @CampusId INT\r\nAS\r\nBEGIN\r\n    INSERT INTO AdmissionApplications (\r\n        ApplicationNumber,\r\n        StudentName,\r\n        Email,\r\n        Phone,\r\n        CourseId,\r\n        CampusId,\r\n        Status\r\n    )\r\n    VALUES (\r\n        @ApplicationNumber,\r\n        @StudentName,\r\n        @Email,\r\n        @Phone,\r\n        @CourseId,\r\n        @CampusId,\r\n        'applied'\r\n    );\r\nEND;\r\nGO\r\n"],"metadata":{"urn":"Server[@Name='DESKTOP-FINRPDH\\SQLEXPRESS']/Database[@Name='CampusAdmissionDB']/StoredProcedure[@Name='sp_CreateAdmissionApplication' and @Schema='dbo']","object_type":"StoredProcedure"}},{"cell_type":"markdown","source":["# [dbo].[sp_DeleteAdmissionApplication]"],"metadata":{"urn":"Server[@Name='DESKTOP-FINRPDH\\SQLEXPRESS']/Database[@Name='CampusAdmissionDB']/StoredProcedure[@Name='sp_DeleteAdmissionApplication' and @Schema='dbo']","object_type":"StoredProcedure"}},{"outputs":[],"execution_count":0,"cell_type":"code","source":["/****** Object:  StoredProcedure [dbo].[sp_DeleteAdmissionApplication]    Script Date: 2/24/2026 3:59:14 PM ******/\r\nSET ANSI_NULLS ON\r\n","GO\r\n","SET QUOTED_IDENTIFIER ON\r\n","GO\r\n","CREATE PROCEDURE [dbo].[sp_DeleteAdmissionApplication]\r\n    @ApplicationId UNIQUEIDENTIFIER\r\nAS\r\nBEGIN\r\n    DELETE FROM AdmissionApplications\r\n    WHERE ApplicationId = @ApplicationId;\r\nEND;\r\nGO\r\n"],"metadata":{"urn":"Server[@Name='DESKTOP-FINRPDH\\SQLEXPRESS']/Database[@Name='CampusAdmissionDB']/StoredProcedure[@Name='sp_DeleteAdmissionApplication' and @Schema='dbo']","object_type":"StoredProcedure"}},{"cell_type":"markdown","source":["# [dbo].[sp_GetAdmissionApplicationById]"],"metadata":{"urn":"Server[@Name='DESKTOP-FINRPDH\\SQLEXPRESS']/Database[@Name='CampusAdmissionDB']/StoredProcedure[@Name='sp_GetAdmissionApplicationById' and @Schema='dbo']","object_type":"StoredProcedure"}},{"outputs":[],"execution_count":0,"cell_type":"code","source":["/****** Object:  StoredProcedure [dbo].[sp_GetAdmissionApplicationById]    Script Date: 2/24/2026 3:59:14 PM ******/\r\nSET ANSI_NULLS ON\r\n","GO\r\n","SET QUOTED_IDENTIFIER ON\r\n","GO\r\n","CREATE PROCEDURE [dbo].[sp_GetAdmissionApplicationById]\r\n    @ApplicationId UNIQUEIDENTIFIER\r\nAS\r\nBEGIN\r\n    SELECT *\r\n    FROM AdmissionApplications\r\n    WHERE ApplicationId = @ApplicationId;\r\n\r\n    SELECT *\r\n    FROM AdmissionDocuments\r\n    WHERE ApplicationId = @ApplicationId;\r\nEND;\r\nGO\r\n"],"metadata":{"urn":"Server[@Name='DESKTOP-FINRPDH\\SQLEXPRESS']/Database[@Name='CampusAdmissionDB']/StoredProcedure[@Name='sp_GetAdmissionApplicationById' and @Schema='dbo']","object_type":"StoredProcedure"}},{"cell_type":"markdown","source":["# [dbo].[sp_GetAdmissionApplications]"],"metadata":{"urn":"Server[@Name='DESKTOP-FINRPDH\\SQLEXPRESS']/Database[@Name='CampusAdmissionDB']/StoredProcedure[@Name='sp_GetAdmissionApplications' and @Schema='dbo']","object_type":"StoredProcedure"}},{"outputs":[],"execution_count":0,"cell_type":"code","source":["/****** Object:  StoredProcedure [dbo].[sp_GetAdmissionApplications]    Script Date: 2/24/2026 3:59:14 PM ******/\r\nSET ANSI_NULLS ON\r\n","GO\r\n","SET QUOTED_IDENTIFIER ON\r\n","GO\r\n","CREATE PROCEDURE [dbo].[sp_GetAdmissionApplications]\r\nAS\r\nBEGIN\r\n    SELECT \r\n        a.ApplicationId,\r\n        a.ApplicationNumber,\r\n        a.StudentName,\r\n        a.Email,\r\n        a.Phone,\r\n        c.CourseName,\r\n        a.Status,\r\n        a.AppliedDate\r\n    FROM AdmissionApplications a\r\n    INNER JOIN Courses c ON a.CourseId = c.CourseId\r\n    ORDER BY a.AppliedDate DESC;\r\nEND;\r\nGO\r\n"],"metadata":{"urn":"Server[@Name='DESKTOP-FINRPDH\\SQLEXPRESS']/Database[@Name='CampusAdmissionDB']/StoredProcedure[@Name='sp_GetAdmissionApplications' and @Schema='dbo']","object_type":"StoredProcedure"}},{"cell_type":"markdown","source":["# [dbo].[sp_GetUserProfile]"],"metadata":{"urn":"Server[@Name='DESKTOP-FINRPDH\\SQLEXPRESS']/Database[@Name='CampusAdmissionDB']/StoredProcedure[@Name='sp_GetUserProfile' and @Schema='dbo']","object_type":"StoredProcedure"}},{"outputs":[],"execution_count":0,"cell_type":"code","source":["/****** Object:  StoredProcedure [dbo].[sp_GetUserProfile]    Script Date: 2/24/2026 3:59:14 PM ******/\r\nSET ANSI_NULLS ON\r\n","GO\r\n","SET QUOTED_IDENTIFIER ON\r\n","GO\r\n","\r\nCREATE PROCEDURE [dbo].[sp_GetUserProfile]\r\n    @UserId INT\r\nAS\r\nBEGIN\r\n    SELECT\r\n        u.UserId,\r\n        up.FullName,\r\n        u.Email,\r\n        r.RoleName,\r\n        up.Phone,\r\n        d.DepartmentName,\r\n        up.AvatarUrl\r\n    FROM Users u\r\n    JOIN UserProfiles up ON u.UserId = up.UserId\r\n    JOIN UserRoles ur ON u.UserId = ur.UserId\r\n    JOIN Roles r ON ur.RoleId = r.RoleId\r\n    LEFT JOIN Departments d ON up.DepartmentId = d.DepartmentId\r\n    WHERE u.UserId = @UserId;\r\nEND;\r\nGO\r\n"],"metadata":{"urn":"Server[@Name='DESKTOP-FINRPDH\\SQLEXPRESS']/Database[@Name='CampusAdmissionDB']/StoredProcedure[@Name='sp_GetUserProfile' and @Schema='dbo']","object_type":"StoredProcedure"}},{"cell_type":"markdown","source":["# [dbo].[sp_Student_ChangeStatus]"],"metadata":{"urn":"Server[@Name='DESKTOP-FINRPDH\\SQLEXPRESS']/Database[@Name='CampusAdmissionDB']/StoredProcedure[@Name='sp_Student_ChangeStatus' and @Schema='dbo']","object_type":"StoredProcedure"}},{"outputs":[],"execution_count":0,"cell_type":"code","source":["/****** Object:  StoredProcedure [dbo].[sp_Student_ChangeStatus]    Script Date: 2/24/2026 3:59:14 PM ******/\r\nSET ANSI_NULLS ON\r\n","GO\r\n","SET QUOTED_IDENTIFIER ON\r\n","GO\r\n","\r\nCREATE PROCEDURE [dbo].[sp_Student_ChangeStatus]\r\n(\r\n    @StudentId INT,\r\n    @Status NVARCHAR(20)\r\n)\r\nAS\r\nBEGIN\r\n    UPDATE Students\r\n    SET Status = @Status, UpdatedAt = SYSDATETIME()\r\n    WHERE StudentId = @StudentId;\r\nEND\r\nGO\r\n"],"metadata":{"urn":"Server[@Name='DESKTOP-FINRPDH\\SQLEXPRESS']/Database[@Name='CampusAdmissionDB']/StoredProcedure[@Name='sp_Student_ChangeStatus' and @Schema='dbo']","object_type":"StoredProcedure"}},{"cell_type":"markdown","source":["# [dbo].[sp_Student_Delete]"],"metadata":{"urn":"Server[@Name='DESKTOP-FINRPDH\\SQLEXPRESS']/Database[@Name='Ca